// === ringbuf.h —— ADT 接口定义 ===
#ifndef RINGBUF_H
#define RINGBUF_H

#include <stdint.h>
#include <stdbool.h>

typedef struct ringbuf {
    uint8_t *data;   /* 缓冲区指针（动态分配） */
    uint16_t size;   /* 容量（2 的幂次方） */
    uint16_t rptr;   /* 读指针（偏移量） */
    uint16_t wptr;   /* 写指针（偏移量） */
    uint16_t count;  /* 已存入字节数 */
} ringbuf_t;

int  ringbuf_init(ringbuf_t *rb, uint8_t *buf, uint16_t sz);
void ringbuf_deinit(ringbuf_t *rb);

/* 生产者调用（DMA 中断或 ISR 中） */
int  ringbuf_push(ringbuf_t *rb, uint8_t byte);
int  ringbuf_push_buf(ringbuf_t *rb, uint8_t *src, uint16_t n);

/* 消费者调用（主循环或任务中） */
int  ringbuf_pop(ringbuf_t *rb, uint8_t *dst);
int  ringbuf_pop_buf(ringbuf_t *rb, uint8_t *dst, uint16_t n);

/* 查询接口（只读，ISR 中可安全调用） */
uint16_t ringbuf_count(const ringbuf_t *rb);
bool     ringbuf_empty(const ringbuf_t *rb);
bool     ringbuf_full(const ringbuf_t *rb);

#endif // RINGBUF_H

// === ringbuf.c —— 核心实现 ===
// 初始化：size 必须是 2 的幂次方
int ringbuf_init(ringbuf_t *rb, uint8_t *buf, uint16_t sz)
{
    if (!buf || (sz & (sz - 1)) != 0) return -1;
    rb->data = buf;
    rb->size = sz;
    rb->rptr = 0;
    rb->wptr = 0;
    rb->count = 0;
    return 0;
}

// 单字节 push（DMA 每字节中断回调用）
int ringbuf_push(ringbuf_t *rb, uint8_t byte)
{
    if (rb->count == rb->size) return -1;  /* 满 */
    rb->data[rb->wptr] = byte;
    rb->wptr = (rb->wptr + 1) & (rb->size - 1);
    rb->count++;
    return 0;
}

// 单字节 pop（主循环中消费用）
int ringbuf_pop(ringbuf_t *rb, uint8_t *dst)
{
    if (rb->count == 0) return -1;  /* 空 */
    *dst = rb->data[rb->rptr];
    rb->rptr = (rb->rptr + 1) & (rb->size - 1);
    rb->count--;
    return 0;
}

/* uart_dma_ring.h */
#ifndef UART_DMA_RING_H
#define UART_DMA_RING_H

#include <stdint.h>
#include <stdbool.h>
#include "stm32xx_hal.h"

#define DMA_BUF_SIZE     1024  /* 2 的幂次方 */
#define HALF_BUF_SIZE    (DMA_BUF_SIZE / 2)
#define RING_BUF_SIZE    2048

typedef struct {
    ringbuf_t ring;             /* 环形缓冲区 */
    uint8_t dma_buf[DMA_BUF_SIZE]; /* DMA 直接写入的缓冲区 */
    uint8_t pending[DMA_BUF_SIZE];/* CPU 暂存 DMA 搬运来的数据 */
    uint16_t half_ptr;          /* 半传输偏移追踪 */
    uint16_t complete_ptr;      /* 完整传输偏移追踪 */
    bool     half_done;         /* 半传输标志 */
    bool     complete_done;     /* 传输完成标志 */
} uart_dma_ring_t;

void uart_dma_ring_init(uart_dma_ring_t *ctx,
                        UART_HandleTypeDef *huart);
void uart_dma_ring_start(uart_dma_ring_t *ctx);
void uart_dma_ring_process(uart_dma_ring_t *ctx);

#endif

/* === uart_dma_ring.c === */
#include "uart_dma_ring.h"

static uint8_t g_dma_buf[DMA_BUF_SIZE];

/* 注意：必须在 DMA 中断优先级 > 此模块中断 */
/* STM32 建议 DMA 中断优先级设最低（最高数字）*/
void uart_dma_ring_init(uart_dma_ring_t *ctx,
                        UART_HandleTypeDef *huart)
{
    /* 初始化环形缓冲区，使用 DMA 缓冲区 */
    ringbuf_init(&ctx->ring, g_dma_buf, DMA_BUF_SIZE);
    ctx->half_ptr = 0;
    ctx->complete_ptr = 0;
    ctx->half_done = false;
    ctx->complete_done = false;
    /* 启动 DMA 接收——单次传输，不会自动循环 */
    HAL_UART_Receive_DMA(huart, ctx->ring.data,
                         DMA_BUF_SIZE);
}

/* 半传输中断回调：DMA 填满了前半部分 */
void HAL_UART_TxHalfCpltCallback(UART_HandleTypeDef *hu)
{
    (void)hu;
    /* 注意：实际应实现 HAL_UART_RxCpltHalfCpltCallback */
    /* 这里用 tx 回调命名仅为演示 HAL 调用约定 */
}

/* DMA 传输完成回调：前半部分已填满 */
void HAL_UART_RxCpltHalfCpltCallback(UART_HandleTypeDef *hu)
{
    (void)hu;
    /* 将前半部分数据搬运到环形缓冲区 */
    /* 关键：从 half_ptr 到 half_ptr + HALF_BUF_SIZE */
    ringbuf_push_buf(&g_dma_ring.ring,
        g_dma_buf + g_dma_ring.half_ptr,
        HALF_BUF_SIZE);
    /* 更新追踪指针 */
    g_dma_ring.half_ptr = (g_dma_ring.half_ptr
        + HALF_BUF_SIZE) % DMA_BUF_SIZE;
    if (g_dma_ring.half_ptr >= DMA_BUF_SIZE)
        g_dma_ring.half_ptr = 0;
}

/* DMA 完全传输回调 */
void HAL_UART_RxCpltCallback(UART_HandleTypeDef *hu)
{
    (void)hu;
    /* 搬运后半部分数据 */
    ringbuf_push_buf(&g_dma_ring.ring,
        g_dma_buf + g_dma_ring.half_ptr,
        HALF_BUF_SIZE);
    /* 重置半传输追踪 */
    g_dma_ring.half_ptr = 0;
    /* ⚠️ 关键步骤：重新启动 DMA 接收 */
    HAL_UART_Receive_DMA(hu, g_dma_buf, DMA_BUF_SIZE);
}

// === 陷阱 1 的修复：正确的缓冲区大小检查 ===
/* ❌ 错误：缓冲区大小不检查，运行时才暴露 */
uint8_t bad_buf[700];  /* 不是 2 的幂次方！ */
ringbuf_init(&rb, bad_buf, 700);
/* 写入时：(ptr + 1) & 699 → 错误偏移！ */

// ✅ 正确：编译时断言 + 运行时验证
#include <assert.h>
#define BUF_SZ 1024  /* 2 的幂次方 */
uint8_t good_buf[BUF_SZ];

void dma_rx_callback(uint8_t byte)
{
    static uint16_t wptr = 0;
    static uint16_t rptr = 0;
    static uint16_t count = 0;

    /* 检查缓冲区是否满了 */
    if (count == BUF_SZ) {
        /* 丢包处理：标记错误而非静默丢弃 */
        error_flags |= ERR_DMA_OVERRUN;
        return;
    }

    /* 位运算掩码：BUF_SZ 必须是 2 的幂次方 */
    good_buf[wptr] = byte;
    wptr = (wptr + 1) & (BUF_SZ - 1);
    count++;
}

