// === 陷阱 4 的修复：内存屏障 ===
/* ARM Cortex-M3/M4 需要 DMB 指令确保顺序 */
void consumer_process(ringbuf_t *rb)
{
    uint16_t available;

    /* 读取 count 之前，确保看到 DMA 最新写入 */
    available = rb->count;  /* volatile 保证可见性 */

    /* ARM DMB 指令：确保前面的 DMA 写完成后才读 */
    __DMB();  /* Data Memory Barrier */

    while (available > 0) {
        uint8_t byte;
        if (ringbuf_pop(&rb->ring, &byte) != 0) break;
        process_byte(byte);  /* 业务逻辑 */
        available--;
    }
}

// === 重构前：DMA 回调大泥球 ===
/* ❌ 150 行回调函数：DMA + 协议解析 + 业务逻辑 */
void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart)
{
    static uint8_t buf[256];
    static uint16_t idx = 0;
    static bool in_frame = false;

    HAL_UART_Receive_IT(huart, &buf[idx], 1);
    idx++;

    if (buf[idx-1] == 0x0A) {  /* 换行符 = 帧结束 */
        if (in_frame) {
            /* 协议 1：Modbus RTU 解析 */
            if (buf[0] == 0x01 && buf[1] == 0x03) {
                modbus_handle(buf, idx);
            }
            /* 协议 2：ASCII 命令解析 */
            else if (buf[0] == '$') {
                ascii_cmd_parse(buf, idx);
            }
            /* 协议 3：二进制帧解析 */
            else if (buf[0] == 0xAA && buf[1] == 0x55) {
                binary_frame_parse(buf, idx);
            }
        }
        in_frame = false;
        idx = 0;
    } else {
        in_frame = true;
        if (idx >= 255) {  /* 缓冲区溢出 */
            idx = 0;
            error_flags |= ERR_FRAME_OVER;
        }
    }
}
