/* layer1: DMA 搬运层 —— 只管数据搬运 */
#include "ringbuf.h"

static ringbuf_t uart_rx_ring;
static uint8_t uart_rx_buf[2048];  /* 2 的幂次方 */

void uart_dma_layer_init(void)
{
    ringbuf_init(&uart_rx_ring, uart_rx_buf, 2048);
    HAL_UART_Receive_DMA(\&huart1,
        uart_rx_buf, 2048);
}

void HAL_UART_RxCpltCallback(UART_HandleTypeDef *hu)
{
    /* DMA 只负责搬运原始字节到环形缓冲区 */
    ringbuf_push_buf(&uart_rx_ring,
        uart_rx_buf, 2048);
    /* 重新启动 DMA */
    HAL_UART_Receive_DMA(hu, uart_rx_buf, 2048);
}

/* layer2: 协议解析层 —— 只管从缓冲区取数据 */
#include "protocol_parser.h"

static bool parse_modbus(uint8_t *data, uint16_t len);
static bool parse_ascii_cmd(uint8_t *data, uint16_t len);

void uart_protocol_layer_process(void)
{
    /* 逐帧读取 */
    while (!ringbuf_empty(&uart_rx_ring)) {
        uint8_t frame[256];
        uint16_t frame_len = 0;

        /* 从环形缓冲区提取完整帧 */
        while (frame_len < sizeof(frame)) {
            uint8_t byte;
            if (ringbuf_pop(&uart_rx_ring, &byte) != 0) break;
            frame[frame_len++] = byte;
            if (byte == 0x0A) break;  /* 帧结束 */
        }

        if (frame_len > 0) {
            /* 根据首字节分发到不同协议解析器 */
            if (frame_len >= 2 && frame[0] == 0x01 && frame[1] == 0x03) {
                parse_modbus(frame, frame_len);
            } else if (frame_len >= 1 && frame[0] == '$') {
                parse_ascii_cmd(frame, frame_len);
            }
            /* 新协议只需在协议层新增一个 else-if */
        }
    }
}
